module top_module(clk, rst, out);input clk;
   input rst;
   output [3:0] out;
   reg [3:0] decrementer;
   assign out =  decrementer;

   always @(posedge clk) begin
      if (rst) begin
         decrementer <= 0;
      end else begin
         decrementer <= decrementer +1;
      end
   end
endmodule
